package com.example.demo.ui;import com.example.demo.dto.UsuarioDTO;import com.example.demo.services.UsuarioService;import com.vaadin.flow.component.button.*;import com.vaadin.flow.component.checkbox.Checkbox;import com.vaadin.flow.component.combobox.ComboBox;import com.vaadin.flow.component.dialog.Dialog;import com.vaadin.flow.component.grid.Grid;import com.vaadin.flow.component.orderedlayout.*;import com.vaadin.flow.component.textfield.*;import com.vaadin.flow.router.*;
@Route(value="usuarios",layout=MainLayout.class) @PageTitle("Usuarios | Franco") public class UsuariosView extends VerticalLayout{
    private final UsuarioService service;private final Grid<UsuarioDTO> grid=new Grid<>(UsuarioDTO.class,false);public UsuariosView(UsuarioService service){this.service=service;addClassName("content-view");setSizeFull();Button add=new Button("Nuevo usuario",e->form(null));add.addThemeVariants(ButtonVariant.LUMO_PRIMARY);grid.addColumn(u->u.nombre()+" "+u.apellido()).setHeader("Nombre");grid.addColumn(UsuarioDTO::email).setHeader("Email");grid.addColumn(UsuarioDTO::dni).setHeader("DNI");grid.addColumn(u->label(u.rol())).setHeader("Perfil");grid.addColumn(u->u.activo()?"Activo":"Inactivo").setHeader("Estado");grid.addComponentColumn(u->new Button("Editar",e->form(u))).setHeader("Acciones");add(ViewSupport.header("Usuarios y permisos",add),grid);expand(grid);refresh();}
    private void refresh(){grid.setItems(service.listar());}private String label(String role){return switch(role){case"USUARIO"->"Cajero";case"ADMIN"->"Encargado";default->"Dueño";};}
    private void form(UsuarioDTO u){Dialog d=new Dialog();d.setHeaderTitle(u==null?"Nuevo usuario":"Editar usuario");TextField name=new TextField("Nombre"),surname=new TextField("Apellido"),email=new TextField("Email");IntegerField dni=new IntegerField("DNI");PasswordField pass=new PasswordField(u==null?"Contraseña":"Nueva contraseña (opcional)");ComboBox<String> role=new ComboBox<>("Perfil");role.setItems("USUARIO","ADMIN","SUPER_ADMIN");role.setItemLabelGenerator(this::label);role.setValue("USUARIO");Checkbox active=new Checkbox("Activo",true);if(u!=null){name.setValue(u.nombre());surname.setValue(u.apellido());email.setValue(u.email());dni.setValue(u.dni());role.setValue(u.rol());active.setValue(u.activo());}d.add(new VerticalLayout(name,surname,dni,email,pass,role,active));Button save=new Button("Guardar",e->{try{service.guardar(u==null?null:u.id(),new UsuarioDTO(u==null?null:u.id(),name.getValue(),surname.getValue(),dni.getValue(),email.getValue(),role.getValue(),active.getValue()),pass.getValue());d.close();refresh();}catch(RuntimeException ex){ViewSupport.error(ex);}});save.addThemeVariants(ButtonVariant.LUMO_PRIMARY);d.getFooter().add(new Button("Cancelar",e->d.close()),save);d.open();}}
